class Solution:
    def minimumCardPickup(self, cards):
        n = len(cards)
        best = -1
        for i in range(n):
            for j in range(i + 1, n):
                if cards[i] == cards[j]:
                    length = j - i + 1
                    if best == -1 or length < best:
                        best = length
                    break
        return best

solutions.python:
class Solution:
    def minimumCardPickup(self, cards):
        last = {}
        best = -1
        for i, c in enumerate(cards):
            if c in last:
                length = i - last[c] + 1
                if best == -1 or length < best:
                    best = length
            last[c] = i
        return best

