var minimumCardPickup = function(cards) {
    const last = new Map();
    let best = -1;
    for (let i = 0; i < cards.length; i++) {
        const c = cards[i];
        if (last.has(c)) {
            const length = i - last.get(c) + 1;
            if (best === -1 || length < best) best = length;
        }
        last.set(c, i);
    }
    return best;
};
